import React, { useEffect, useState } from 'react';
import { Wifi, WifiOff, Signal, SignalMedium, SignalLow } from 'lucide-react';
import {
    Tooltip,
    TooltipContent,
    TooltipProvider,
    TooltipTrigger,
} from '@/components/ui/tooltip';

interface NetworkInformation extends EventTarget {
    readonly downlink: number;
    readonly effectiveType: 'slow-2g' | '2g' | '3g' | '4g';
    readonly rtt: number;
    readonly saveData: boolean;
    onchange: EventListener | null;
    addEventListener: (type: string, listener: EventListener) => void;
    removeEventListener: (type: string, listener: EventListener) => void;
}

const NetworkQualityIndicator: React.FC = () => {
    const [connection, setConnection] = useState<NetworkInformation | null>(null);
    const [isOnline, setIsOnline] = useState(navigator.onLine);

    useEffect(() => {
        const nav = navigator as any;
        const conn = nav.connection || nav.mozConnection || nav.webkitConnection;

        if (conn) {
            setConnection(conn);
            const updateConnection = () => {
                setConnection({ ...conn }); // Force update
            };
            conn.addEventListener('change', updateConnection);
            return () => conn.removeEventListener('change', updateConnection);
        }
    }, []);

    useEffect(() => {
        const handleOnline = () => setIsOnline(true);
        const handleOffline = () => setIsOnline(false);

        window.addEventListener('online', handleOnline);
        window.addEventListener('offline', handleOffline);

        return () => {
            window.removeEventListener('online', handleOnline);
            window.removeEventListener('offline', handleOffline);
        };
    }, []);

    if (!isOnline) {
        return (
            <TooltipProvider>
                <Tooltip>
                    <TooltipTrigger asChild>
                        <div className='flex items-center justify-center h-8 w-8 rounded-full bg-red-500/10 text-red-500'>
                            <WifiOff className='h-4 w-4' />
                        </div>
                    </TooltipTrigger>
                    <TooltipContent>
                        <p>You are offline</p>
                    </TooltipContent>
                </Tooltip>
            </TooltipProvider>
        );
    }

    if (!connection) {
        // Fallback if API not supported
        return (
            <TooltipProvider>
                <Tooltip>
                    <TooltipTrigger asChild>
                        <div className='flex items-center justify-center h-8 w-8 rounded-full bg-green-500/10 text-green-500'>
                            <Wifi className='h-4 w-4' />
                        </div>
                    </TooltipTrigger>
                    <TooltipContent>
                        <p>Online (Details unavailable)</p>
                    </TooltipContent>
                </Tooltip>
            </TooltipProvider>
        );
    }

    const getQualityIcon = () => {
        if (connection.rtt > 500 || connection.downlink < 1) {
            return <SignalLow className='h-4 w-4 text-red-500' />;
        }
        if (connection.rtt > 150 || connection.downlink < 5) {
            return <SignalMedium className='h-4 w-4 text-yellow-500' />;
        }
        return <Signal className='h-4 w-4 text-green-500' />;
    };

    const getQualityText = () => {
        if (connection.rtt > 500 || connection.downlink < 1) return 'Poor Connection';
        if (connection.rtt > 150 || connection.downlink < 5) return 'Fair Connection';
        return 'Good Connection';
    };

    const getQualityColor = () => {
        if (connection.rtt > 500 || connection.downlink < 1) return 'bg-red-500/10';
        if (connection.rtt > 150 || connection.downlink < 5) return 'bg-yellow-500/10';
        return 'bg-green-500/10';
    };

    return (
        <TooltipProvider>
            <Tooltip>
                <TooltipTrigger asChild>
                    <div className={`flex items-center justify-center h-8 w-8 rounded-full ${getQualityColor()} cursor-help transition-colors`}>
                        {getQualityIcon()}
                    </div>
                </TooltipTrigger>
                <TooltipContent>
                    <div className='text-xs space-y-1'>
                        <p className='font-semibold'>{getQualityText()}</p>
                        <p>Type: {connection.effectiveType?.toUpperCase() || 'UNKNOWN'}</p>
                        <p>Downlink: ~{connection.downlink || 0} Mbps</p>
                        <p>RTT: {connection.rtt || 0} ms</p>
                    </div>
                </TooltipContent>
            </Tooltip>
        </TooltipProvider>
    );
};

export default NetworkQualityIndicator;

import React, { useState, useEffect } from 'react';
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogHeader,
    DialogTitle,
} from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { useOrganization } from '@/contexts/OrganizationContext';
import { supabase } from '@/integrations/supabase/client';
import { Trash2, UserPlus, Shield, User } from 'lucide-react';
import { toast } from 'sonner';

interface OrganizationSettingsModalProps {
    open: boolean;
    onOpenChange: (open: boolean) => void;
}

type Member = {
    user_id: string;
    role: 'owner' | 'admin' | 'member';
    profiles?: {
        display_name: string | null;
        email?: string; // Not usually available in profiles unless public
    };
};

export const OrganizationSettingsModal: React.FC<OrganizationSettingsModalProps> = ({
    open,
    onOpenChange,
}) => {
    const { currentOrganization, addMember, removeMember } = useOrganization();
    const [members, setMembers] = useState<Member[]>([]);
    const [newMemberId, setNewMemberId] = useState('');
    const [isLoading, setIsLoading] = useState(false);

    const fetchMembers = async () => {
        if (!currentOrganization) return;
        try {
            const { data, error } = await supabase
                .from('organization_members')
                .select(`
          user_id,
          role,
          profiles:user_id (
            display_name
          )
        `)
                .eq('organization_id', currentOrganization.id);

            if (error) throw error;
            setMembers(data as any);
        } catch (error) {
            console.error('Error fetching members:', error);
        }
    };

    useEffect(() => {
        if (open && currentOrganization) {
            fetchMembers();
        }
    }, [open, currentOrganization]);

    const handleAddMember = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!newMemberId) return;

        setIsLoading(true);
        try {
            await addMember(newMemberId);
            setNewMemberId('');
            fetchMembers();
        } catch (error) {
            // Error handled in context
        } finally {
            setIsLoading(false);
        }
    };

    const handleRemoveMember = async (userId: string) => {
        if (!confirm('Are you sure you want to remove this member?')) return;
        try {
            await removeMember(userId);
            fetchMembers();
        } catch (error) {
            // Error handled in context
        }
    };

    if (!currentOrganization) return null;

    return (
        <Dialog open={open} onOpenChange={onOpenChange}>
            <DialogContent className="sm:max-w-[600px]">
                <DialogHeader>
                    <DialogTitle>Organization Settings</DialogTitle>
                    <DialogDescription>
                        Manage members for {currentOrganization.name}
                    </DialogDescription>
                </DialogHeader>

                <div className="space-y-6">
                    <div className="space-y-4">
                        <h4 className="text-sm font-medium">Add Member</h4>
                        <form onSubmit={handleAddMember} className="flex gap-2">
                            <div className="flex-1">
                                <Label htmlFor="user-id" className="sr-only">User ID</Label>
                                <Input
                                    id="user-id"
                                    placeholder="Enter User ID to add..."
                                    value={newMemberId}
                                    onChange={(e) => setNewMemberId(e.target.value)}
                                />
                            </div>
                            <Button type="submit" disabled={isLoading}>
                                <UserPlus className="w-4 h-4 mr-2" />
                                Add
                            </Button>
                        </form>
                        <p className="text-xs text-muted-foreground">
                            Ask the user for their User ID (found in their profile/dashboard).
                        </p>
                    </div>

                    <div className="space-y-4">
                        <h4 className="text-sm font-medium">Members ({members.length})</h4>
                        <div className="border rounded-lg divide-y">
                            {members.map((member) => (
                                <div key={member.user_id} className="flex items-center justify-between p-3">
                                    <div className="flex items-center gap-3">
                                        <div className="p-2 bg-muted rounded-full">
                                            <User className="w-4 h-4" />
                                        </div>
                                        <div>
                                            <p className="font-medium text-sm">
                                                {member.profiles?.display_name || 'Unknown User'}
                                            </p>
                                            <p className="text-xs text-muted-foreground font-mono">
                                                {member.user_id}
                                            </p>
                                        </div>
                                    </div>
                                    <div className="flex items-center gap-2">
                                        <span className={`text-xs px-2 py-1 rounded-full ${member.role === 'owner' ? 'bg-primary/10 text-primary' : 'bg-muted text-muted-foreground'
                                            }`}>
                                            {member.role}
                                        </span>
                                        {member.role !== 'owner' && (
                                            <Button
                                                variant="ghost"
                                                size="icon"
                                                className="text-destructive hover:text-destructive/90"
                                                onClick={() => handleRemoveMember(member.user_id)}
                                            >
                                                <Trash2 className="w-4 h-4" />
                                            </Button>
                                        )}
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>
                </div>
            </DialogContent>
        </Dialog>
    );
};

import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from '@/components/ui/dialog';
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from '@/components/ui/alert-dialog';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Switch } from '@/components/ui/switch';
import { Separator } from '@/components/ui/separator';
import {
  Settings,
  LogOut,
  ShieldAlert,
  Edit,
  Lock,
  Trash2,
  Mic,
  Video,
  Copy,
  Check,
  Globe,
  Link as LinkIcon,
} from 'lucide-react';
import { useState, useEffect } from 'react';
import { useWebSocket } from '@/hooks/useWebSocket';
import { useNavigate } from 'react-router-dom';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';

interface SettingsModalProps {
  roomId: string;
  isHost: boolean;
}

const SettingsModal = ({ roomId, isHost }: SettingsModalProps) => {
  const {
    leaveRoom,
    disbandRoom,
    updateRoomSettings,
    roomName: currentRoomName,
    toggleRoomLock,
    isRoomLocked,
    changeVideoDevice,
    changeAudioDevice,
    selectedVideoDeviceId,
    selectedAudioDeviceId,
    hasWaitingRoom,
    accessType,
    inviteToken,
  } = useWebSocket();
  const navigate = useNavigate();
  const [open, setOpen] = useState(false);
  const [showDisbandConfirm, setShowDisbandConfirm] = useState(false);
  const [videoDevices, setVideoDevices] = useState<MediaDeviceInfo[]>([]);
  const [audioDevices, setAudioDevices] = useState<MediaDeviceInfo[]>([]);
  const [copiedToken, setCopiedToken] = useState(false);

  useEffect(() => {
    if (open) {
      navigator.mediaDevices.enumerateDevices().then((devices) => {
        setVideoDevices(devices.filter((d) => d.kind === 'videoinput'));
        setAudioDevices(devices.filter((d) => d.kind === 'audioinput'));
      });
    }
  }, [open]);

  // Room settings state (for host)
  const [newRoomName, setNewRoomName] = useState(currentRoomName || '');
  const [newPassword, setNewPassword] = useState('');
  const [removePassword, setRemovePassword] = useState(false);
  const [enableWaitingRoom, setEnableWaitingRoom] = useState(hasWaitingRoom || false);
  const [selectedAccessType, setSelectedAccessType] = useState<'public' | 'password' | 'invite' | 'organization'>(
    accessType || 'public'
  );

  // Sync state when modal opens, but don't overwrite while editing to avoid cursor jumps
  useEffect(() => {
    if (open) {
      setNewRoomName(currentRoomName || '');
      setSelectedAccessType(accessType || 'public');
      setEnableWaitingRoom(hasWaitingRoom || false);
    }
  }, [open, currentRoomName, accessType, hasWaitingRoom]);

  // Debounced save for text inputs
  useEffect(() => {
    if (!open || !isHost) return;

    const timer = setTimeout(() => {
      // Only save if changed from current
      if (newRoomName !== currentRoomName || (newPassword && newPassword.length > 0)) {
        updateRoomSettings(
          newRoomName.trim() || undefined,
          removePassword ? '' : (newPassword.trim() || undefined),
          enableWaitingRoom,
          selectedAccessType
        );
      }
    }, 800);

    return () => clearTimeout(timer);
  }, [newRoomName, newPassword, removePassword, open, isHost]); // Exclude others to avoid double save

  // Immediate save for toggles (triggered by their handlers, or separate effect)
  // We'll use a separate effect for these that runs immediately
  useEffect(() => {
    if (!open || !isHost) return;
    // Skip initial mount check if values match props? No, just save.
    // Actually, if we just opened, we don't want to save immediately if values match.
    // But updateRoomSettings is cheap if no change?
    // Let's rely on user interaction to change state.

    // Check if values differ from props before saving to avoid initial save on open
    if (enableWaitingRoom !== hasWaitingRoom || selectedAccessType !== accessType || removePassword) {
      updateRoomSettings(
        newRoomName.trim() || undefined,
        removePassword ? '' : (newPassword.trim() || undefined),
        enableWaitingRoom,
        selectedAccessType
      );
    }
  }, [enableWaitingRoom, selectedAccessType, removePassword]);

  const handleLeave = () => {
    leaveRoom();
    navigate('/dashboard');
  };

  const handleDisband = () => {
    if (confirm('Are you sure you want to disband this room? All participants will be removed.')) {
      disbandRoom();
      navigate('/dashboard');
    }
  };

  const copyInviteToken = () => {
    if (inviteToken) {
      navigator.clipboard.writeText(
        `${window.location.origin}/room/${roomId}?token=${inviteToken}`
      );
      setCopiedToken(true);
      setTimeout(() => setCopiedToken(false), 2000);
    }
  };

  return (
    <Dialog open={open} onOpenChange={setOpen}>
      <DialogTrigger asChild>
        <Button
          variant='ghost'
          size='icon'
          className='text-zinc-400 hover:text-white hover:bg-zinc-800'
          aria-label="Room Settings"
        >
          <Settings className='h-5 w-5' />
        </Button>
      </DialogTrigger>
      <DialogContent className='sm:max-w-[500px] bg-zinc-950 border-zinc-800 text-zinc-100 p-0 overflow-hidden gap-0'>
        <DialogHeader className='p-6 pb-4 bg-zinc-950 border-b border-zinc-800'>
          <DialogTitle className='text-xl font-semibold'>Room Settings</DialogTitle>
          <DialogDescription className='text-zinc-400'>
            Manage your preferences and room controls.
          </DialogDescription>
        </DialogHeader>

        <div className='p-6 space-y-6 overflow-y-auto max-h-[70vh]'>
          {/* Host-only Room Settings (Moved to Top) */}
          {isHost && (
            <div className='space-y-4'>
              <h4 className='text-sm font-medium text-zinc-400 uppercase tracking-wider flex items-center gap-2'>
                <Edit className='h-3 w-3' /> Room Settings
              </h4>

              <div className='space-y-4 p-4 rounded-xl bg-zinc-900/30 border border-zinc-800'>
                <div className='space-y-2'>
                  <Label htmlFor='room-name' className='text-zinc-300'>
                    Room Name
                  </Label>
                  <Input
                    id='room-name'
                    value={newRoomName}
                    onChange={(e) => setNewRoomName(e.target.value)}
                    placeholder='Enter new room name'
                    className='bg-zinc-900 border-zinc-700 text-zinc-100 focus:border-primary/50'
                  />
                </div>

                <div className='space-y-3'>
                  <Label className='text-zinc-300'>Access Type</Label>
                  <div className='grid grid-cols-3 gap-2'>
                    {[
                      {
                        id: 'public',
                        label: 'Public',
                        icon: Globe,
                        color: 'text-blue-400',
                        bg: 'bg-blue-400/10',
                        border: 'border-blue-400/50'
                      },
                      {
                        id: 'password',
                        label: 'Private',
                        icon: Lock,
                        color: 'text-amber-400',
                        bg: 'bg-amber-400/10',
                        border: 'border-amber-400/50'
                      },
                      {
                        id: 'invite',
                        label: 'Invite',
                        icon: LinkIcon,
                        color: 'text-purple-400',
                        bg: 'bg-purple-400/10',
                        border: 'border-purple-400/50'
                      }
                    ].map((type) => (
                      <div
                        key={type.id}
                        onClick={() => setSelectedAccessType(type.id as any)}
                        className={`
                          cursor-pointer rounded-lg border p-2 flex flex-col items-center gap-1 transition-all duration-200
                          ${selectedAccessType === type.id
                            ? `${type.border} ${type.bg}`
                            : 'border-zinc-800 hover:bg-zinc-800/50'
                          }
                        `}
                      >
                        <type.icon className={`w-4 h-4 ${selectedAccessType === type.id ? type.color : 'text-zinc-400'}`} />
                        <span className={`text-xs font-medium ${selectedAccessType === type.id ? 'text-zinc-200' : 'text-zinc-400'}`}>
                          {type.label}
                        </span>
                      </div>
                    ))}
                  </div>
                </div>

                {selectedAccessType === 'password' && (
                  <div className='space-y-2'>
                    <Label htmlFor='room-password' className='text-zinc-300'>
                      Change Password
                    </Label>
                    <Input
                      id='room-password'
                      type='password'
                      value={newPassword}
                      onChange={(e) => setNewPassword(e.target.value)}
                      placeholder='New password (leave empty to keep)'
                      disabled={removePassword}
                      className='bg-zinc-900 border-zinc-700 text-zinc-100 focus:border-primary/50'
                    />
                    <div className='flex items-center space-x-2 pt-1'>
                      <Switch
                        id='remove-password'
                        checked={removePassword}
                        onCheckedChange={setRemovePassword}
                      />
                      <Label
                        htmlFor='remove-password'
                        className='text-sm text-zinc-400 cursor-pointer'
                      >
                        Remove password protection
                      </Label>
                    </div>
                  </div>
                )}

                {selectedAccessType === 'invite' && inviteToken && (
                  <div className='space-y-2'>
                    <Label className='text-zinc-300'>Invite Link</Label>
                    <div className='flex items-center gap-2'>
                      <Input
                        readOnly
                        value={`${window.location.origin}/room/${roomId}?token=${inviteToken}`}
                        className='bg-zinc-900 border-zinc-700 text-zinc-400'
                      />
                      <Button size='icon' variant='outline' onClick={copyInviteToken}>
                        {copiedToken ? (
                          <Check className='h-4 w-4 text-green-500' />
                        ) : (
                          <Copy className='h-4 w-4' />
                        )}
                      </Button>
                    </div>
                    <p className='text-xs text-zinc-500'>
                      Only users with this specific link can join.
                    </p>
                  </div>
                )}

                <div className='flex items-center justify-between p-3 rounded-lg bg-zinc-900 border border-zinc-800'>
                  <div className='flex flex-col space-y-1'>
                    <Label htmlFor='waiting-room' className='text-zinc-200 font-medium'>
                      Waiting Room
                    </Label>
                    <span className='text-xs text-zinc-500'>
                      Participants must be admitted by host
                    </span>
                  </div>
                  <Switch
                    id='waiting-room'
                    checked={enableWaitingRoom}
                    onCheckedChange={setEnableWaitingRoom}
                    className='data-[state=checked]:bg-primary'
                  />
                </div>
              </div>
            </div>
          )}

          {/* Device Settings */}
          <div className='space-y-4'>
            <h4 className='text-sm font-medium text-zinc-400 uppercase tracking-wider flex items-center gap-2'>
              <Settings className='h-3 w-3' /> Device Settings
            </h4>
            <div className='space-y-4 p-4 rounded-xl bg-zinc-900/30 border border-zinc-800'>
              <div className='space-y-2'>
                <Label className='text-zinc-300 flex items-center gap-2'>
                  <Video className='h-4 w-4' /> Camera
                </Label>
                <Select
                  value={selectedVideoDeviceId || undefined}
                  onValueChange={changeVideoDevice}
                >
                  <SelectTrigger className='bg-zinc-900 border-zinc-700 text-zinc-100'>
                    <SelectValue placeholder='Select Camera' />
                  </SelectTrigger>
                  <SelectContent>
                    {videoDevices
                      .filter((device) => device.deviceId && device.deviceId.trim() !== '')
                      .map((device) => (
                        <SelectItem key={device.deviceId} value={device.deviceId}>
                          {device.label || `Camera ${device.deviceId.slice(0, 5)}...`}
                        </SelectItem>
                      ))}
                  </SelectContent>
                </Select>
              </div>

              <div className='space-y-2'>
                <Label className='text-zinc-300 flex items-center gap-2'>
                  <Mic className='h-4 w-4' /> Microphone
                </Label>
                <Select
                  value={selectedAudioDeviceId || undefined}
                  onValueChange={changeAudioDevice}
                >
                  <SelectTrigger className='bg-zinc-900 border-zinc-700 text-zinc-100'>
                    <SelectValue placeholder='Select Microphone' />
                  </SelectTrigger>
                  <SelectContent>
                    {audioDevices
                      .filter((device) => device.deviceId && device.deviceId.trim() !== '')
                      .map((device) => (
                        <SelectItem key={device.deviceId} value={device.deviceId}>
                          {device.label || `Microphone ${device.deviceId.slice(0, 5)}...`}
                        </SelectItem>
                      ))}
                  </SelectContent>
                </Select>
              </div>
            </div>
          </div>

          {/* Host Controls */}
          {isHost && (
            <div className='space-y-4'>
              <h4 className='text-sm font-medium text-red-400 uppercase tracking-wider flex items-center gap-2'>
                <ShieldAlert className='h-3 w-3' /> Host Controls
              </h4>

              <div className='p-4 rounded-xl bg-red-950/10 border border-red-900/20 space-y-4'>
                <div className='flex items-center justify-between'>
                  <div className='flex items-center space-x-3'>
                    <div className='p-2 rounded-full bg-red-900/20 text-red-400'>
                      <Lock className='h-4 w-4' />
                    </div>
                    <div className='flex flex-col'>
                      <Label htmlFor='lock-room' className='font-medium text-red-100'>
                        Lock Room
                      </Label>
                      <span className='text-xs text-red-400/70'>
                        Prevent new participants from joining
                      </span>
                    </div>
                  </div>
                  <Switch
                    id='lock-room'
                    checked={isRoomLocked}
                    onCheckedChange={toggleRoomLock}
                    className='data-[state=checked]:bg-red-600'
                  />
                </div>
              </div>
            </div>
          )}
        </div>

        <div className='p-4 bg-zinc-950 border-t border-zinc-800'>
          {isHost ? (
            <Button
              variant='destructive'
              className='w-full bg-red-600 hover:bg-red-700 text-white font-medium h-11'
              onClick={() => setShowDisbandConfirm(true)}
            >
              <Trash2 className='mr-2 h-4 w-4' />
              Disband Room
            </Button>
          ) : (
            <Button
              variant='destructive'
              className='w-full bg-red-600 hover:bg-red-700 text-white font-medium h-11'
              onClick={handleLeave}
            >
              <LogOut className='mr-2 h-4 w-4' />
              Leave Room
            </Button>
          )}
        </div>
      </DialogContent>

      <AlertDialog open={showDisbandConfirm} onOpenChange={setShowDisbandConfirm}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Disband Room</AlertDialogTitle>
            <AlertDialogDescription>
              Are you sure you want to disband this room? All participants will be removed. This
              action cannot be undone.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancel</AlertDialogCancel>
            <AlertDialogAction
              onClick={() => {
                disbandRoom();
                navigate('/dashboard');
              }}
              className='bg-red-600 hover:bg-red-700 text-white'
            >
              Disband Room
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </Dialog>
  );
};

export default SettingsModal;

import React from 'react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import { Badge } from '@/components/ui/badge';
import {
    DropdownMenu,
    DropdownMenuContent,
    DropdownMenuItem,
    DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu';
import {
    Send,
    Paperclip,
    File as FileIcon,
    Users,
    MessageSquare,
    MoreVertical,
    Download,
    Monitor,
} from 'lucide-react';
import { format } from 'date-fns';
import { User, Message, FileData } from '@/types/websocket';

interface ChatItem {
    id: string;
    userId: string;
    userName: string;
    timestamp: Date | string;
    content?: string;
    isFile?: boolean;
    url?: string;
    name?: string;
    size?: number;
    type?: string;
}

interface ChatPanelProps {
    showChat: boolean;
    activeTab: 'chat' | 'participants';
    setActiveTab: (tab: 'chat' | 'participants') => void;
    messages: Message[];
    files: FileData[];
    users: User[];
    currentUser: User | undefined;
    isHost: boolean;
    waitingUsers: User[];
    admitUser: (userId: string) => void;
    denyUser: (userId: string) => void;
    admitAllWaitingUsers: () => void;
    promoteToCoHost: (userId: string) => void;
    demoteFromCoHost: (userId: string) => void;
    muteUser: (userId: string) => void;
    kickUser: (userId: string) => void;
    messagesEndRef: React.RefObject<HTMLDivElement>;
    handleSendMessage: (e: React.FormEvent) => void;
    newMessage: string;
    setNewMessage: (message: string) => void;
    fileInputRef: React.RefObject<HTMLInputElement>;
    handleFileUpload: (e: React.ChangeEvent<HTMLInputElement>) => void;
    triggerFileUpload: () => void;
    isUploading: boolean;
    presentFile: (file: FileData) => void;
}

const ChatPanel: React.FC<ChatPanelProps> = ({
    showChat,
    activeTab,
    setActiveTab,
    messages,
    files,
    users,
    currentUser,
    isHost,
    waitingUsers,
    admitUser,
    denyUser,
    admitAllWaitingUsers,
    promoteToCoHost,
    demoteFromCoHost,
    muteUser,
    kickUser,
    messagesEndRef,
    handleSendMessage,
    newMessage,
    setNewMessage,
    fileInputRef,
    handleFileUpload,
    triggerFileUpload,
    isUploading,
    presentFile,
}) => {
    return (
        <div
            className={`fixed right-0 top-16 bottom-0 w-full md:w-80 bg-background border-l transition-transform duration-300 flex flex-col z-40 ${showChat ? 'translate-x-0' : 'translate-x-full'
                }`}
        >
            {/* Tabs */}
            <div className='flex items-center border-b'>
                <Button
                    variant='ghost'
                    className={`flex-1 rounded-none border-b-2 ${activeTab === 'chat'
                        ? 'border-primary text-primary'
                        : 'border-transparent text-muted-foreground'
                        }`}
                    onClick={() => setActiveTab('chat')}
                >
                    <MessageSquare className='w-4 h-4 mr-2' /> Chat
                </Button>
                <Button
                    variant='ghost'
                    className={`flex-1 rounded-none border-b-2 ${activeTab === 'participants'
                        ? 'border-primary text-primary'
                        : 'border-transparent text-muted-foreground'
                        }`}
                    onClick={() => setActiveTab('participants')}
                >
                    <Users className='w-4 h-4 mr-2' /> Participants
                    {waitingUsers.length > 0 && (
                        <Badge
                            variant='destructive'
                            className='ml-2 h-5 w-5 p-0 flex items-center justify-center rounded-full text-[10px]'
                        >
                            {waitingUsers.length}
                        </Badge>
                    )}
                </Button>
            </div>

            {/* Tab Content */}
            <div className='flex-1 overflow-hidden flex flex-col'>
                {activeTab === 'chat' ? (
                    // Chat Tab
                    <div className='flex-1 flex flex-col h-full'>
                        <ScrollArea className='flex-1 p-4'>
                            <div className='space-y-4'>
                                {[
                                    ...messages,
                                    ...files.map((f) => ({
                                        ...f,
                                        id: `file-${f.id}`,
                                        isFile: true,
                                        content: f.name,
                                    })),
                                ]
                                    .sort(
                                        (a, b) =>
                                            new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime()
                                    )
                                    .map((item: unknown) => {
                                        const chatItem = item as ChatItem;
                                        const isSystemMessage = chatItem.userId === 'system';
                                        if (isSystemMessage) {
                                            return (
                                                <div key={chatItem.id} className='flex justify-center my-2'>
                                                    <div className='bg-muted/50 px-4 py-1 rounded-full'>
                                                        <span className='text-xs text-muted-foreground'>
                                                            {chatItem.content}
                                                        </span>
                                                    </div>
                                                </div>
                                            );
                                        }
                                        return (
                                            <div key={chatItem.id} className='flex gap-3'>
                                                <Avatar className='h-8 w-8 mt-1'>
                                                    <AvatarImage
                                                        src={`https://api.dicebear.com/7.x/avataaars/svg?seed=${chatItem.userName}`}
                                                    />
                                                    <AvatarFallback>
                                                        {chatItem.userName.substring(0, 2).toUpperCase()}
                                                    </AvatarFallback>
                                                </Avatar>
                                                <div className='flex flex-col gap-1 max-w-[85%]'>
                                                    <div className='flex items-baseline gap-2'>
                                                        <span className='text-sm font-semibold'>
                                                            {chatItem.userName}
                                                        </span>
                                                        <span className='text-xs text-muted-foreground'>
                                                            {format(new Date(chatItem.timestamp), 'HH:mm')}
                                                        </span>
                                                    </div>
                                                    {chatItem.isFile ? (
                                                        (() => {
                                                            const fileUrl = chatItem.url!.startsWith('http')
                                                                ? chatItem.url
                                                                : `${import.meta.env.VITE_WS_URL || 'http://localhost:3001'
                                                                }${chatItem.url}`;
                                                            return (
                                                                <div className='flex flex-col gap-2'>
                                                                    <div className='bg-muted p-3 rounded-lg rounded-tl-none border flex items-center gap-3 group hover:bg-muted/80 transition-colors'>
                                                                        <div
                                                                            className='bg-background p-2 rounded-md cursor-pointer'
                                                                            onClick={() => window.open(fileUrl, '_blank')}
                                                                        >
                                                                            <FileIcon className='w-6 h-6 text-primary' />
                                                                        </div>
                                                                        <div
                                                                            className='flex-1 min-w-0 cursor-pointer'
                                                                            onClick={() => window.open(fileUrl, '_blank')}
                                                                        >
                                                                            <p className='text-sm font-medium text-primary underline-offset-4 group-hover:underline truncate'>
                                                                                {chatItem.name}
                                                                            </p>
                                                                            <p className='text-xs text-muted-foreground'>
                                                                                {(chatItem.size! / 1024).toFixed(1)} KB
                                                                            </p>
                                                                        </div>
                                                                        <Button
                                                                            variant='ghost'
                                                                            size='icon'
                                                                            className='h-8 w-8'
                                                                            title='Download'
                                                                            onClick={(e) => {
                                                                                e.stopPropagation();
                                                                                const link = document.createElement('a');
                                                                                link.href = fileUrl!;
                                                                                link.download = chatItem.name!;
                                                                                link.target = '_blank';
                                                                                document.body.appendChild(link);
                                                                                link.click();
                                                                                document.body.removeChild(link);
                                                                            }}
                                                                        >
                                                                            <Download className='h-4 w-4' />
                                                                        </Button>
                                                                    </div>
                                                                    {(isHost || currentUser?.isCoHost) &&
                                                                        /\.(mp4|webm|ogg)$/i.test(chatItem.name!) && (
                                                                            <Button
                                                                                size='sm'
                                                                                variant='secondary'
                                                                                className='w-full'
                                                                                onClick={() => presentFile(chatItem as any)}
                                                                            >
                                                                                <Monitor className='w-4 h-4 mr-2' /> Play in Stage
                                                                            </Button>
                                                                        )}
                                                                </div>
                                                            );
                                                        })()
                                                    ) : (
                                                        <div className='bg-primary/10 p-3 rounded-lg rounded-tl-none text-sm'>
                                                            {chatItem.content}
                                                        </div>
                                                    )}
                                                </div>
                                            </div>
                                        );
                                    })}
                                <div ref={messagesEndRef} />
                            </div>
                        </ScrollArea>
                        <div className='p-4 border-t bg-background/50 backdrop-blur-sm'>
                            <form onSubmit={handleSendMessage} className='flex gap-2'>
                                <input
                                    type='file'
                                    ref={fileInputRef}
                                    className='hidden'
                                    onChange={handleFileUpload}
                                />
                                <Button
                                    type='button'
                                    variant='ghost'
                                    size='icon'
                                    onClick={triggerFileUpload}
                                    disabled={isUploading}
                                >
                                    <Paperclip className='w-5 h-5 text-muted-foreground' />
                                </Button>
                                <Input
                                    value={newMessage}
                                    onChange={(e) => setNewMessage(e.target.value)}
                                    placeholder='Type a message...'
                                    className='flex-1'
                                />
                                <Button type='submit' size='icon' disabled={!newMessage.trim()}>
                                    <Send className='w-5 h-5' />
                                </Button>
                            </form>
                        </div>
                    </div>
                ) : (
                    <ScrollArea className='flex-1 p-4'>
                        {waitingUsers.length > 0 && (
                            <div className='mb-6'>
                                <h3 className='text-xs font-semibold text-muted-foreground uppercase tracking-wider mb-3'>
                                    Waiting Room ({waitingUsers.length})
                                </h3>
                                <div className='space-y-4'>
                                    {waitingUsers.map((user) => (
                                        <div
                                            key={user.id}
                                            className='flex items-center justify-between p-2 rounded-lg bg-muted/50'
                                        >
                                            <div className='flex items-center gap-2'>
                                                <Avatar className='h-8 w-8'>
                                                    <AvatarImage
                                                        src={`https://api.dicebear.com/7.x/avataaars/svg?seed=${user.name}`}
                                                    />
                                                    <AvatarFallback>{user.name[0]}</AvatarFallback>
                                                </Avatar>
                                                <div className='flex flex-col'>
                                                    <span className='text-sm font-medium'>{user.name}</span>
                                                    <span className='text-xs text-muted-foreground'>Waiting...</span>
                                                </div>
                                            </div>
                                            <div className='flex items-center gap-1'>
                                                <Button
                                                    size='icon'
                                                    variant='ghost'
                                                    className='h-7 w-7 text-green-500 hover:text-green-600 hover:bg-green-500/10'
                                                    onClick={() => admitUser(user.id)}
                                                >
                                                    <span className='sr-only'>Admit</span>
                                                    <Users className='h-4 w-4' />
                                                </Button>
                                                <Button
                                                    size='icon'
                                                    variant='ghost'
                                                    className='h-7 w-7 text-red-500 hover:text-red-600 hover:bg-red-500/10'
                                                    onClick={() => denyUser(user.id)}
                                                >
                                                    <span className='sr-only'>Deny</span>
                                                    <Users className='h-4 w-4 rotate-45' />
                                                </Button>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                                <div className='flex justify-end mt-2'>
                                    <Button
                                        variant='outline'
                                        size='sm'
                                        onClick={admitAllWaitingUsers}
                                        className='text-xs'
                                    >
                                        Admit All
                                    </Button>
                                </div>
                                <div className='h-px bg-border my-4' />
                            </div>
                        )}

                        <h3 className='text-xs font-semibold text-muted-foreground uppercase tracking-wider mb-3'>
                            In Meeting ({users.length})
                        </h3>
                        <div className='space-y-4'>
                            {users.map((participant) => (
                                <div
                                    key={participant.id}
                                    className={`flex items-center gap-3 p-2 rounded-lg ${participant.isHost
                                        ? 'bg-primary/10 border border-primary/20'
                                        : participant.isCoHost
                                            ? 'bg-secondary/50 border border-secondary'
                                            : ''
                                        }`}
                                >
                                    <Avatar className='h-8 w-8'>
                                        <AvatarImage
                                            src={`https://api.dicebear.com/7.x/avataaars/svg?seed=${participant.name}`}
                                        />
                                        <AvatarFallback>
                                            {participant.name.substring(0, 2).toUpperCase()}
                                        </AvatarFallback>
                                    </Avatar>
                                    <div className='flex flex-col flex-1'>
                                        <span className='text-sm font-medium leading-none'>
                                            {participant.name}
                                        </span>
                                        <span className='text-xs text-muted-foreground'>Online</span>
                                    </div>
                                    {participant.isHost && (
                                        <Badge variant='default' className='text-xs'>
                                            Host
                                        </Badge>
                                    )}
                                    {participant.isCoHost && !participant.isHost && (
                                        <Badge variant='secondary' className='text-xs'>
                                            Co-Host
                                        </Badge>
                                    )}
                                    {(isHost || users.find((u) => u.id === users[0]?.id)?.isCoHost) &&
                                        !participant.isHost && (
                                            <DropdownMenu>
                                                <DropdownMenuTrigger asChild>
                                                    <Button variant='ghost' size='icon' className='h-6 w-6'>
                                                        <MoreVertical className='h-4 w-4' />
                                                    </Button>
                                                </DropdownMenuTrigger>
                                                <DropdownMenuContent align='end'>
                                                    {participant.isCoHost ? (
                                                        <DropdownMenuItem
                                                            onClick={() => demoteFromCoHost(participant.id)}
                                                        >
                                                            Demote from Co-Host
                                                        </DropdownMenuItem>
                                                    ) : (
                                                        <DropdownMenuItem
                                                            onClick={() => promoteToCoHost(participant.id)}
                                                        >
                                                            Promote to Co-Host
                                                        </DropdownMenuItem>
                                                    )}
                                                    <DropdownMenuItem onClick={() => muteUser(participant.id)}>
                                                        Mute User
                                                    </DropdownMenuItem>
                                                    <DropdownMenuItem
                                                        onClick={() => kickUser(participant.id)}
                                                        className='text-red-600 focus:text-red-600 focus:bg-red-100'
                                                    >
                                                        Kick User
                                                    </DropdownMenuItem>
                                                </DropdownMenuContent>
                                            </DropdownMenu>
                                        )}
                                </div>
                            ))}
                        </div>
                    </ScrollArea>
                )}
            </div>
        </div>
    );
};

export default ChatPanel;

import React, { createContext, useContext, useEffect, useState } from 'react';
import { useAuth } from '@/hooks/useAuth';
import { supabase } from '@/integrations/supabase/client';
import { toast } from 'sonner';

export type Organization = {
    id: string;
    name: string;
    slug: string;
    owner_id: string;
    created_at: string;
    role?: 'owner' | 'admin' | 'member';
};

type OrganizationContextType = {
    organizations: Organization[];
    currentOrganization: Organization | null;
    setCurrentOrganization: (org: Organization | null) => void;
    isLoading: boolean;
    createOrganization: (name: string, slug: string) => Promise<void>;
    refreshOrganizations: () => Promise<void>;
    addMember: (userId: string, role?: 'admin' | 'member') => Promise<void>;
    removeMember: (userId: string) => Promise<void>;
};

const OrganizationContext = createContext<OrganizationContextType | undefined>(undefined);

export const OrganizationProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const { user } = useAuth();
    const [organizations, setOrganizations] = useState<Organization[]>([]);
    const [currentOrganization, setCurrentOrganization] = useState<Organization | null>(null);
    const [isLoading, setIsLoading] = useState(true);

    const fetchOrganizations = async () => {
        if (!user) {
            setOrganizations([]);
            setCurrentOrganization(null);
            setIsLoading(false);
            return;
        }

        try {
            setIsLoading(true);
            const { data, error } = await supabase
                .from('organizations')
                .select(`
          *,
          organization_members!inner (
            role
          )
        `)
                .eq('organization_members.user_id', user.id);

            if (error) throw error;

            const orgs = data.map((org: any) => ({
                ...org,
                role: org.organization_members[0]?.role,
            }));

            setOrganizations(orgs);

            // Restore selected org from local storage or default to first
            const savedOrgId = localStorage.getItem('selectedOrgId');
            if (savedOrgId) {
                const savedOrg = orgs.find((o: Organization) => o.id === savedOrgId);
                if (savedOrg) setCurrentOrganization(savedOrg);
                else if (orgs.length > 0) setCurrentOrganization(orgs[0]);
            } else if (orgs.length > 0) {
                setCurrentOrganization(orgs[0]);
            }
        } catch (error) {
            console.error('Error fetching organizations:', error);
            toast.error('Failed to load organizations');
        } finally {
            setIsLoading(false);
        }
    };

    useEffect(() => {
        fetchOrganizations();
    }, [user]);

    useEffect(() => {
        if (currentOrganization) {
            localStorage.setItem('selectedOrgId', currentOrganization.id);
        } else {
            localStorage.removeItem('selectedOrgId');
        }
    }, [currentOrganization]);

    const createOrganization = async (name: string, slug: string) => {
        if (!user) return;

        try {
            const { data, error } = await supabase
                .from('organizations')
                .insert({
                    name,
                    slug,
                    owner_id: user.id,
                })
                .select()
                .single();

            if (error) throw error;

            toast.success('Organization created successfully');
            await fetchOrganizations();
            setCurrentOrganization({ ...data, role: 'owner' }); // Optimistic update
        } catch (error: any) {
            console.error('Error creating organization:', error);
            if (error.code === '23505') { // Unique violation
                toast.error('Organization slug already exists');
            } else {
                toast.error('Failed to create organization');
            }
            throw error;
        }
    };

    const addMember = async (userId: string, role: 'admin' | 'member' = 'member') => {
        if (!currentOrganization) return;
        try {
            const { error } = await supabase
                .from('organization_members')
                .insert({
                    organization_id: currentOrganization.id,
                    user_id: userId,
                    role,
                });

            if (error) throw error;
            toast.success('Member added successfully');
            await fetchOrganizations();
        } catch (error) {
            console.error('Error adding member:', error);
            toast.error('Failed to add member');
            throw error;
        }
    };

    const removeMember = async (userId: string) => {
        if (!currentOrganization) return;
        try {
            const { error } = await supabase
                .from('organization_members')
                .delete()
                .eq('organization_id', currentOrganization.id)
                .eq('user_id', userId);

            if (error) throw error;
            toast.success('Member removed successfully');
            await fetchOrganizations();
        } catch (error) {
            console.error('Error removing member:', error);
            toast.error('Failed to remove member');
            throw error;
        }
    };

    return (
        <OrganizationContext.Provider
            value={{
                organizations,
                currentOrganization,
                setCurrentOrganization,
                isLoading,
                createOrganization,
                refreshOrganizations: fetchOrganizations,
                addMember,
                removeMember,
            }}
        >
            {children}
        </OrganizationContext.Provider>
    );
};

export const useOrganization = () => {
    const context = useContext(OrganizationContext);
    if (context === undefined) {
        throw new Error('useOrganization must be used within an OrganizationProvider');
    }
    return context;
};

import React, { createContext, useContext, useEffect, useState, useCallback, useRef } from 'react';
import { useAuth } from '@/hooks/useAuth';
import { toast } from '@/hooks/use-toast';
import { useNavigate } from 'react-router-dom';
import { SignalingService, type SignalingEvents } from '@/lib/signaling';
import { SFUManager } from '@/lib/SFUManager';
import { User, Message, FileData, RoomInfo } from '@/types/websocket';
import { WebSocketContext, WebSocketState, WebSocketContextType } from './WebSocketContextValue';
import { useMediaStream } from './WebSocket/useMediaStream';
import { useSocketEvents } from './WebSocket/useSocketEvents';

export { type WebSocketState, type WebSocketContextType };

// ICE servers will be fetched from backend
const DEFAULT_ICE_SERVERS = {
  iceServers: [{ urls: 'stun:stun.l.google.com:19302' }],
};

export const WebSocketProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [state, setState] = useState<WebSocketState>({
    isConnected: false,
    roomId: null,
    roomName: null,
    users: [],
    messages: [],
    files: [],
    error: null,
    isHost: false,
    localStream: null,
    localScreenStream: null,
    remoteStreams: new Map(),
    remoteScreenStreams: new Map(),
    isAudioEnabled: false,
    isVideoEnabled: false,
    isScreenSharing: false,
    presentedFile: null,
    isPresentingFile: false,
    presenterName: null,
    isRoomLocked: false,
    youtubeVideoId: null,
    isYoutubePlaying: false,
    youtubeStatus: 'closed',
    youtubeCurrentTime: 0,
    selectedVideoDeviceId: localStorage.getItem('preferredVideoDeviceId'),
    selectedAudioDeviceId: localStorage.getItem('preferredAudioDeviceId'),
    isMediaLoading: false,
    hasWaitingRoom: false,
    waitingUsers: [],
    isWaiting: false,
    accessType: 'public',
    inviteToken: null,
  });

  const stateRef = useRef(state);
  useEffect(() => {
    stateRef.current = state;
  }, [state]);

  // Services
  const signalingRef = useRef<SignalingService | null>(null);
  const sfuManagerRef = useRef<SFUManager | null>(null);
  const screenShareStreamIdsRef = useRef<Map<string, string>>(new Map()); // userId -> streamId
  const enableMediaRef = useRef<(() => Promise<void>) | null>(null);

  // Initialize services
  useEffect(() => {
    const url = import.meta.env.VITE_WS_URL || 'http://localhost:3001';
    signalingRef.current = new SignalingService(url);

    try {
      sfuManagerRef.current = new SFUManager(signalingRef.current, (userId, track, kind) => {
        setState((prev) => {
          const stream = new MediaStream([track]);
          const newRemoteStreams = new Map(prev.remoteStreams);
          let existingStream = newRemoteStreams.get(userId);

          if (!existingStream) {
            existingStream = new MediaStream();
            newRemoteStreams.set(userId, existingStream);
          }

          existingStream.addTrack(track);

          return { ...prev, remoteStreams: newRemoteStreams };
        });
      });
    } catch (error) {
      console.error('Failed to initialize SFUManager:', error);
    }

    signalingRef.current.connect();

    return () => {
      signalingRef.current?.disconnect();
      sfuManagerRef.current?.closeAll();
    };
  }, []);

  // Use split hooks
  const {
    enableMedia,
    toggleAudio,
    toggleVideo,
    startScreenShare,
    stopScreenShare,
  } = useMediaStream({
    sfuManagerRef,
    setLocalStream: (stream) => setState(prev => ({ ...prev, localStream: stream })),
    setLocalScreenStream: (stream) => setState(prev => ({ ...prev, localScreenStream: stream })),
    setIsAudioEnabled: (enabled) => setState(prev => ({ ...prev, isAudioEnabled: enabled })),
    setIsVideoEnabled: (enabled) => setState(prev => ({ ...prev, isVideoEnabled: enabled })),
    setIsScreenSharing: (sharing) => setState(prev => ({ ...prev, isScreenSharing: sharing })),
    setIsMediaLoading: (loading) => setState(prev => ({ ...prev, isMediaLoading: loading })),
  });

  // Store enableMedia in ref so it can be called from event handlers
  useEffect(() => {
    enableMediaRef.current = enableMedia;
  }, [enableMedia]);

  useSocketEvents({
    signalingRef,
    sfuManagerRef,
    state,
    setState,
    enableMediaRef,
    user: user ? {
      id: user.id,
      name: user.user_metadata?.display_name || user.email?.split('@')[0] || 'Guest',
    } : null,
  });

  // Methods
  const joinRoom = useCallback(
    (
      roomId: string,
      password?: string,
      inviteToken?: string,
      onSuccess?: () => void,
      onError?: (error: string) => void
    ) => {
      const userData = {
        id: user?.id,
        name: user?.user_metadata?.display_name || user?.email?.split('@')[0] || 'Guest',
      };
      signalingRef.current?.emit(
        'join-room',
        { roomId, password, inviteToken, user: userData },
        (response: any) => {
          if (!response.success) {
            if (onError) {
              onError(response.error || 'Unknown error');
            } else {
              setState((prev) => ({ ...prev, error: response.error || 'Unknown error' }));
              toast({ title: 'Join Failed', description: response.error, variant: 'destructive' });
            }
          } else if (response.room) {
            const roomData = response.room;
            setState((prev) => ({
              ...prev,
              roomId: roomData.id,
              roomName: roomData.name || roomData.id,
              users: roomData.users,
              messages: roomData.messages,
              files: roomData.files,
              isHost: roomData.isHost,
              hasWaitingRoom: roomData.hasWaitingRoom || false,
              waitingUsers: roomData.waitingUsers || [],
              isWaiting: false,
              accessType: roomData.accessType || 'public',
              inviteToken: roomData.inviteToken || null,
              error: null,
            }));
            if (onSuccess) onSuccess();
          } else if (response.error === 'waiting') {
            setState((prev) => ({ ...prev, isWaiting: true, error: null }));
            if (onSuccess) onSuccess();
          }
        }
      );
    },
    [user]
  );

  const createRoom = useCallback(
    (
      roomId: string,
      roomName: string,
      password?: string,
      accessType: 'public' | 'password' | 'invite' | 'organization' = 'public',
      onSuccess?: () => void,
      orgId?: string
    ) => {
      const userData = {
        id: user?.id,
        name: user?.user_metadata?.display_name || user?.email?.split('@')[0] || 'Guest',
      };

      const handleSuccess = (data: { roomId: string }) => {
        if (data.roomId === roomId) {
          joinRoom(roomId, password, undefined, onSuccess);
          signalingRef.current?.off('create-success' as keyof SignalingEvents, handleSuccess);
        }
      };
      signalingRef.current?.on('create-success' as keyof SignalingEvents, handleSuccess);

      signalingRef.current?.emit('create-room', {
        roomId,
        roomName,
        password,
        accessType,
        user: userData,
        orgId,
      });
    },
    [user, joinRoom]
  );


  const sendMessage = useCallback((content: string) => {
    if (state.roomId && user) {
      const messageData = {
        roomId: state.roomId,
        message: {
          content,
        },
      };
      signalingRef.current?.emit('send-message', messageData, (response: any) => {
        if (!response.success) {
          toast({ title: 'Error', description: 'Failed to send message', variant: 'destructive' });
        }
      });
    }
  }, [state.roomId, user]);


  const uploadFile = useCallback(async (file: File): Promise<boolean> => {
    if (!state.roomId || !user) return false;

    return new Promise((resolve) => {
      const reader = new FileReader();
      reader.onload = (e) => {
        if (e.target?.result) {
          const fileData = {
            id: crypto.randomUUID(),
            userId: user.id,
            userName: user.user_metadata?.display_name || user.email?.split('@')[0] || 'Guest',
            name: file.name,
            size: file.size,
            type: file.type,
            content: e.target.result, // Base64 content
            timestamp: new Date(),
          };

          signalingRef.current?.emit('upload-file', { roomId: state.roomId!, file: fileData }, (response: any) => {
            if (response.success) {
              resolve(true);
            } else {
              toast({ title: 'Upload Failed', description: response.error, variant: 'destructive' });
              resolve(false);
            }
          });
        }
      };
      reader.readAsDataURL(file);
    });
  }, [state.roomId, user]);

  const sendFile = uploadFile;

  const leaveRoom = useCallback(() => {
    if (state.roomId) {
      signalingRef.current?.emit('leave-room', { roomId: state.roomId });
      sfuManagerRef.current?.closeAll();
      setState((prev) => ({
        ...prev,
        roomId: null,
        roomName: null,
        users: [],
        messages: [],
        files: [],
        isHost: false,
        localStream: null,
        remoteStreams: new Map(),
      }));
      navigate('/dashboard');
    }
  }, [state.roomId, navigate]);

  const disbandRoom = useCallback(() => {
    if (state.roomId && state.isHost) {
      signalingRef.current?.emit('disband-room', { roomId: state.roomId });
    }
  }, [state.roomId, state.isHost]);

  const kickUser = useCallback((userId: string) => {
    if (state.roomId && state.isHost) {
      signalingRef.current?.emit('kick-user', { roomId: state.roomId, userId });
    }
  }, [state.roomId, state.isHost]);

  const updateRoomSettings = useCallback((roomName?: string, password?: string, hasWaitingRoom?: boolean, accessType?: 'public' | 'password' | 'invite') => {
    if (state.roomId && state.isHost) {
      const settings = { roomName, password, hasWaitingRoom, accessType };
      signalingRef.current?.emit('update-room-settings', { roomId: state.roomId, settings });
    }
  }, [state.roomId, state.isHost]);

  const admitUser = useCallback((userId: string) => {
    if (state.roomId && state.isHost) {
      signalingRef.current?.emit('admit-user', { roomId: state.roomId, userId });
    }
  }, [state.roomId, state.isHost]);

  const denyUser = useCallback((userId: string) => {
    if (state.roomId && state.isHost) {
      signalingRef.current?.emit('deny-user', { roomId: state.roomId, userId });
    }
  }, [state.roomId, state.isHost]);

  const admitAllWaitingUsers = useCallback(() => {
    if (state.roomId && state.isHost) {
      state.waitingUsers.forEach((user) => {
        signalingRef.current?.emit('admit-user', { roomId: state.roomId, userId: user.id });
      });
    }
  }, [state.roomId, state.isHost, state.waitingUsers]);

  const toggleRoomLock = useCallback(() => {
    if (state.roomId && state.isHost) {
      signalingRef.current?.emit('toggle-room-lock', { roomId: state.roomId });
    }
  }, [state.roomId, state.isHost]);

  const startYoutubeVideo = useCallback((videoId: string) => {
    if (state.roomId) {
      signalingRef.current?.emit('start-youtube', { roomId: state.roomId, videoId });
    }
  }, [state.roomId]);

  const stopYoutubeVideo = useCallback(() => {
    if (state.roomId) {
      signalingRef.current?.emit('close-youtube', { roomId: state.roomId });
    }
  }, [state.roomId]);

  const playYoutubeVideo = useCallback((time: number) => {
    if (state.roomId) {
      signalingRef.current?.emit('play-youtube', { roomId: state.roomId, time });
    }
  }, [state.roomId]);

  const pauseYoutubeVideo = useCallback((time: number) => {
    if (state.roomId) {
      signalingRef.current?.emit('pause-youtube', { roomId: state.roomId, time });
    }
  }, [state.roomId]);

  const seekYoutubeVideo = useCallback((time: number) => {
    if (state.roomId) {
      signalingRef.current?.emit('seek-youtube', { roomId: state.roomId, time });
    }
  }, [state.roomId]);

  const promoteToCoHost = useCallback((userId: string) => {
    if (state.roomId && state.isHost) {
      signalingRef.current?.emit('promote-to-cohost', { roomId: state.roomId, userId });
    }
  }, [state.roomId, state.isHost]);

  const demoteFromCoHost = useCallback((userId: string) => {
    if (state.roomId && state.isHost) {
      signalingRef.current?.emit('demote-from-cohost', { roomId: state.roomId, userId });
    }
  }, [state.roomId, state.isHost]);

  const changeVideoDevice = useCallback(async (deviceId: string) => {
    localStorage.setItem('preferredVideoDeviceId', deviceId);
    setState(prev => ({ ...prev, selectedVideoDeviceId: deviceId }));
    if (state.localStream) {
      // Restart media to use new device
      state.localStream.getTracks().forEach(t => t.stop());
      await enableMedia();
    }
  }, [state.localStream, enableMedia]);

  const changeAudioDevice = useCallback(async (deviceId: string) => {
    localStorage.setItem('preferredAudioDeviceId', deviceId);
    setState(prev => ({ ...prev, selectedAudioDeviceId: deviceId }));
    if (state.localStream) {
      state.localStream.getTracks().forEach(t => t.stop());
      await enableMedia();
    }
  }, [state.localStream, enableMedia]);

  const muteUser = useCallback((userId: string) => {
    if (state.roomId && state.isHost) {
      signalingRef.current?.emit('mute-user', { roomId: state.roomId, userId });
    }
  }, [state.roomId, state.isHost]);

  const getRecentRooms = useCallback((callback?: (rooms: unknown[]) => void) => {
    // Placeholder for getting recent rooms, maybe via API or socket
    console.log('getRecentRooms called');
    if (callback) callback([]);
  }, []);

  const closePresentedFile = useCallback(() => {
    if (state.roomId) {
      signalingRef.current?.emit('stop-presentation', { roomId: state.roomId });
      setState(prev => ({ ...prev, presentedFile: null, isPresentingFile: false, presenterName: null }));
    }
  }, [state.roomId]);

  const clearError = useCallback(() => {
    setState(prev => ({ ...prev, error: null }));
  }, []);

  const value: WebSocketContextType = {
    ...state,
    socket: signalingRef.current?.rawSocket || null,
    signaling: signalingRef.current,
    joinRoom,
    createRoom,
    leaveRoom,
    sendMessage,
    uploadFile,
    sendFile,
    toggleAudio,
    toggleVideo,
    startScreenShare,
    stopScreenShare,
    disbandRoom,
    kickUser,
    muteUser,
    updateRoomSettings,
    admitUser,
    denyUser,
    admitAllWaitingUsers,
    toggleRoomLock,
    startYoutubeVideo,
    stopYoutubeVideo,
    playYoutubeVideo,
    pauseYoutubeVideo,
    seekYoutubeVideo,
    promoteToCoHost,
    demoteFromCoHost,
    changeVideoDevice,
    changeAudioDevice,
    getRecentRooms,
    closePresentedFile,
    clearError,
    enableMedia,
    presentFile: (file: FileData) => {
      // Implement presentFile if not already defined or imported?
      // Wait, presentFile is in the interface but I don't see it in the file.
      // It should be implemented.
      if (state.roomId) {
        signalingRef.current?.emit('present-file', { roomId: state.roomId, file });
      }
    },
    toggleScreenShare: () => {
      // Implement toggleScreenShare if needed, or alias to start/stop
      if (state.isScreenSharing) {
        stopScreenShare();
      } else {
        startScreenShare();
      }
    }
  };

  return (
    <WebSocketContext.Provider value={value}>
      {children}
    </WebSocketContext.Provider>
  );
};

import { createContext } from 'react';
import { type Socket } from 'socket.io-client';
import { User, Message, FileData } from '@/types/websocket';

export interface WebSocketState {
    isConnected: boolean;
    roomId: string | null;
    roomName: string | null;
    users: User[];
    messages: Message[];
    files: FileData[];
    error: string | null;
    isHost: boolean;
    localStream: MediaStream | null;
    localScreenStream: MediaStream | null;
    remoteStreams: Map<string, MediaStream>;
    remoteScreenStreams: Map<string, MediaStream>;
    isAudioEnabled: boolean;
    isVideoEnabled: boolean;
    isScreenSharing: boolean;
    presentedFile: FileData | null;
    isPresentingFile: boolean;
    presenterName: string | null;
    isRoomLocked: boolean;
    youtubeVideoId: string | null;
    isYoutubePlaying: boolean;
    youtubeStatus: 'playing' | 'paused' | 'closed';
    youtubeCurrentTime: number;
    selectedVideoDeviceId: string | null;
    selectedAudioDeviceId: string | null;
    isMediaLoading: boolean;
    hasWaitingRoom: boolean;
    waitingUsers: User[];
    isWaiting: boolean;
